const prev = $('Geschichte parsen').first().json;
const rawText = $input.item.json.text || '';

let wortschatz = [], tags = [];
try {
  const m = rawText.match(/\{[\s\S]*\}/);
  if (m) { const p = JSON.parse(m[0]); wortschatz = p.wortschatz || []; tags = p.tags || []; }
} catch(e) { tags = [prev.genre]; }

return { json: { ...prev, wortschatz, tags } };

const prev = $('Linguistik parsen').first().json;
const rawText = $input.item.json.text || '';

let quizData = [];
try { const m = rawText.match(/\[[\s\S]*\]/); if (m) quizData = JSON.parse(m[0]); } catch(e) {}

return { json: { ...prev, quizData } };

// Skip bei imageCount 0 (Test-Modus)
const prevData = $('Bildszenen vorbereiten').first().json;
if (prevData.skipImages || prevData.imageCount === 0) {
  return [{ json: { ...prevData, _skipLoop: true } }];
}

const prev = $('Bildszenen vorbereiten').first().json;
const rawText = $input.first().json.text || '';
const charRef = prev.characterReference || '';

let scenes = [];
try { const m = rawText.match(/\[[\s\S]*\]/); if (m) scenes = JSON.parse(m[0]); } catch(e) {}

if (!Array.isArray(scenes) || scenes.length === 0) {
  scenes = [{ scene: 1, prompt: "Children's book watercolor illustration, soft pastel colors, a friendly scene from the story '" + prev.title + "', child-safe" }];
}

return scenes.map(s => {
  let finalPrompt = s.prompt;
  if (charRef && !finalPrompt.includes(charRef.substring(0, 30))) {
    finalPrompt = charRef + '. Scene: ' + finalPrompt;
  }
  return {
    json: {
      ...prev,
      sceneIndex: s.scene,
      imagePrompt: finalPrompt,
      imageFilename: prev.slug + '-' + s.scene + '.png',
      imageGithubPath: 'bilder/' + prev.slug + '-' + s.scene + '.png',
      geminiRequestBody: {
        contents: [{ role: 'user', parts: [{ text: finalPrompt }] }],
        generationConfig: { responseModalities: ['image', 'text'] }
      }
    }
  };
});

const data = $('Quiz parsen').first().json;
let template = $input.item.json.data;

// Generate image tags for all images (1 to imageCount)
const imageCount = data.imageCount || 1;
let imagesHtml = '';
for (let i = 1; i <= imageCount; i++) {
  const imgUrl = `https://rala84.github.io/lesekumpel/bilder/${data.slug}-${i}.png`;
  imagesHtml += `<img src="${imgUrl}" alt="${data.title}" class="hero-image" onerror="this.style.display='none'">
        `;
}

template = template
  .replace(/\{\{STORY_TITLE\}\}/g, data.title)
  .replace(/\{\{STORY_DATE\}\}/g, data.date)
  .replace(/\{\{PERSONA_NAME\}\}/g, data.personaName)
  .replace(/\{\{PERSONA_IMG_URL\}\}/g, data.personaImg)
  .replace(/\{\{PERSONA_BIO\}\}/g, data.personaBio)
  .replace(/\{\{STUFE\}\}/g, String(data.stufe))
  .replace(/\{\{STUFE_LABEL\}\}/g, data.stufeLabel || '')
  .replace(/\{\{NEUROTYPE\}\}/g, data.neurotype)
  .replace(/\{\{GENRE\}\}/g, data.genre)
  .replace(/\{\{STORY_IMAGES_HTML\}\}/g, imagesHtml.trim())
  .replace(/\{\{HERO_IMAGE_URL\}\}/g, `https://rala84.github.io/lesekumpel/bilder/${data.slug}-1.png`)
  .replace(/\{\{RAW_STORY_TEXT\}\}/g, JSON.stringify(data.storyText || ''))
  .replace(/\{\{EMOJI_STORY_TEXT\}\}/g, JSON.stringify(data.emojiStoryText || data.storyText || ''))
  .replace(/\{\{RAW_SUMMARY_TEXT\}\}/g, JSON.stringify(data.summaryText || ''))
  .replace(/\{\{QUIZ_DATA_JSON\}\}/g, JSON.stringify(data.quizData || []))
  .replace(/\{\{DICTIONARY_JSON\}\}/g, JSON.stringify(data.wortschatz || []))
  .replace(/\{\{WORD_COUNT\}\}/g, String(data.wordCount || 0))
  .replace(/\{\{SLUG\}\}/g, data.slug)
  .replace(/\{\{RELATED_STORIES_HTML\}\}/g, '');

const htmlBase64 = Buffer.from(template, 'utf8').toString('base64');
const storyUrl = `https://rala84.github.io/lesekumpel/demo-texte/${data.slug}.html`;

return { json: { ...data, htmlBase64, filePath: `demo-texte/${data.slug}.html`, commitMessage: `Demo-Text: ${data.title} — ${data.personaName} Stufe ${data.stufe}`, storyUrl } };

const d = $input.item.json;
const elementsUserPrompt = `Analyze this German children's story and extract ALL visual elements needed to illustrate it consistently.

Output ONLY a JSON object (no markdown, no explanation):
{
  "characters": [
    {
      "name": "Character name",
      "role": "main/supporting",
      "appearance": "Detailed English description: age, gender, hair color+style, skin tone, eye color, clothing with colors and details, distinguishing features, body type"
    }
  ],
  "props": [
    {
      "name": "Item name",
      "description": "Detailed English visual description with colors, size, shape, material"
    }
  ],
  "setting": "Detailed English description of the main location, time of day, weather, key environmental details"
}

Be VERY specific about visual details. If the story doesn't mention a detail (like hair color), invent one and keep it consistent.
Every character MUST have: hair color+style, clothing colors, at least one distinguishing feature.

Story:
${d.storyText}`;
return { json: { ...d, elementsUserPrompt } };

const prev = $('Story-Elemente vorbereiten').first().json;
const rawText = $input.first().json.text || '';

let storyElements = { characters: [], props: [], setting: '' };
try {
  const m = rawText.match(/\{[\s\S]*\}/);
  if (m) storyElements = JSON.parse(m[0]);
} catch(e) {}

let charRef = '';
if (storyElements.characters && storyElements.characters.length > 0) {
  charRef = storyElements.characters
    .map(c => c.name + ': ' + c.appearance)
    .join('. ');
}
if (storyElements.props && storyElements.props.length > 0) {
  charRef += '. Props: ' + storyElements.props
    .map(p => p.name + ': ' + p.description)
    .join('. ');
}
if (storyElements.setting) {
  charRef += '. Setting: ' + storyElements.setting;
}

return { json: { ...prev, storyElements, characterReference: charRef } };

// Hole Original-Daten von 'Daten vorbereiten' und den LLM-Output
const original = $('Daten vorbereiten').item.json;
const enriched = ($input.item.json.text || '').trim();

// Ersetze die Kurzbeschreibung im userPrompt
let userPrompt = original.userPrompt;
if (enriched && enriched.length > 5) {
  userPrompt = userPrompt.replace(
    /Kurzbeschreibung: .*/,
    'Kurzbeschreibung: ' + enriched
  );
}

// Gib alle Original-Felder zurück mit aktualisiertem Prompt
return {
  json: {
    ...original,
    descriptionOriginal: original.description,
    description: enriched || original.description,
    userPrompt
  }
};

const prev = $('Geschichte parsen').first().json;
const responseText = $input.item.json.text || '';

const storyMatch = responseText.match(/TEXT:\s*([\s\S]*?)(?=ZUSAMMENFASSUNG:|$)/);
const summaryMatch = responseText.match(/ZUSAMMENFASSUNG:\s*([\s\S]*)/);
const storyMatchOld = responseText.match(/GESCHICHTE:\s*([\s\S]*?)(?=ZUSAMMENFASSUNG:|$)/);

const rawStory = storyMatch ? storyMatch[1].trim()
  : storyMatchOld ? storyMatchOld[1].trim()
  : responseText.trim();
const summaryText = summaryMatch ? summaryMatch[1].trim() : prev.summaryText;

// Silbentrennung
function silbentrennung(wort) {
  if (wort.length <= 3) return wort;
  if (!/^[a-z\u00e4\u00f6\u00fc\u00df]+$/i.test(wort)) return wort;
  const w = wort.toLowerCase();
  const einheiten = [];
  let i = 0;
  while (i < w.length) {
    if (i+2 < w.length && w.substring(i, i+3) === 'sch') { einheiten.push({text:w.substring(i,i+3),typ:'K',pos:i,len:3}); i+=3; continue; }
    const zwei = i+1<w.length ? w.substring(i,i+2) : '';
    if (['ch','ck','ph','th','qu','pf'].includes(zwei)) { einheiten.push({text:zwei,typ:'K',pos:i,len:2}); i+=2; continue; }
    if (['ei','au','eu','\u00e4u','ie','ai'].includes(zwei)) { einheiten.push({text:zwei,typ:'V',pos:i,len:2}); i+=2; continue; }
    const vokal = 'aeiouy\u00e4\u00f6\u00fc'.includes(w[i]);
    einheiten.push({text:w[i],typ:vokal?'V':'K',pos:i,len:1}); i++;
  }
  const vokalIndices = [];
  for (let e=0; e<einheiten.length; e++) {
    if (einheiten[e].typ==='V') {
      if (vokalIndices.length>0 && vokalIndices[vokalIndices.length-1].end===e) vokalIndices[vokalIndices.length-1].end=e+1;
      else vokalIndices.push({start:e,end:e+1});
    }
  }
  if (vokalIndices.length<2) return wort;
  const trennstellen = [];
  for (let v=0; v<vokalIndices.length-1; v++) {
    const nachVokal = vokalIndices[v].end;
    const vorVokal = vokalIndices[v+1].start;
    const anzahlKons = vorVokal - nachVokal;
    let trennEinheit;
    if (anzahlKons===0) trennEinheit=nachVokal;
    else if (anzahlKons===1) trennEinheit=nachVokal;
